const fs = require('fs');

function compute_loan_metrics(loan) {
  const principal = loan.principal;
  const annual_rate_pct = loan.annual_rate_pct;
  const term_months = loan.term_months;
  const origination_fee = loan.origination_fee;

  // Calculate monthly rate (no rounding)
  const monthly_rate = annual_rate_pct / 100 / 12;

  // Calculate monthly payment
  let monthly_payment;
  if (monthly_rate === 0) {
    monthly_payment = principal / term_months;
  } else {
    const rate_factor = Math.pow(1 + monthly_rate, term_months);
    monthly_payment = (principal * monthly_rate * rate_factor) / (rate_factor - 1);
  }

  // Round to 2 decimal places
  monthly_payment = Math.round(monthly_payment * 100) / 100;

  // Calculate total interest
  let total_interest = Math.round((monthly_payment * term_months - principal) * 100) / 100;

  // Calculate total paid
  let total_paid = Math.round((principal + total_interest + origination_fee) * 100) / 100;

  // Build discrepancies list
  const discrepancies = [];

  // Check monthly_payment
  if (monthly_payment !== loan.stated_monthly_payment) {
    discrepancies.push({
      field: 'monthly_payment',
      stated: loan.stated_monthly_payment,
      computed: monthly_payment,
      delta: Math.round((monthly_payment - loan.stated_monthly_payment) * 100) / 100
    });
  }

  // Check total_interest
  if (total_interest !== loan.stated_total_interest) {
    discrepancies.push({
      field: 'total_interest',
      stated: loan.stated_total_interest,
      computed: total_interest,
      delta: Math.round((total_interest - loan.stated_total_interest) * 100) / 100
    });
  }

  // Check total_paid
  if (total_paid !== loan.stated_total_paid) {
    discrepancies.push({
      field: 'total_paid',
      stated: loan.stated_total_paid,
      computed: total_paid,
      delta: Math.round((total_paid - loan.stated_total_paid) * 100) / 100
    });
  }

  return {
    loan_id: loan.loan_id,
    lender: loan.lender,
    computed: {
      monthly_payment: monthly_payment,
      total_interest: total_interest,
      total_paid: total_paid
    },
    discrepancies: discrepancies,
    valid: discrepancies.length === 0
  };
}

// Load the loan data
const loan = JSON.parse(fs.readFileSync('/var/folders/1q/vdr_cj816z314xnj3bp7w_wr0000gn/T/capture-loan_calculator-46g4w5q8/loan_calculator/sample_inputs/loan_012.json', 'utf8'));

